}

import { type Task } from 'wasp/entities'
import { type CreateTask, type TogglePriority } from 'wasp/server/operations'

type CreateTaskArgs = {
  description: string
}

export const createTask: CreateTask<CreateTaskArgs, Task> = async (args, context) => {
  return context.entities.Task.create({
    data: {
      description: args.description,
      priority: 'Low'
    }
  })
}

type TogglePriorityArgs = {
  id: number
}

export const togglePriority: TogglePriority<TogglePriorityArgs, Task> = async (args, context) => {
  const task = await context.entities.Task.findUnique({
    where: { id: args.id }
  })
  if (!task) {
    throw new Error('Task not found')
  }
  return context.entities.Task.update({
    where: { id: args.id },
    data: {
      priority: task.priority === 'Low' ? 'High' : 'Low'
    }
  })
}

