import { useQuery, useAction, getTasks, createTask, togglePriority } from 'wasp/client/operations'
import { FormEvent } from 'react'
import "./Main.css";

export function MainPage() {
  const { data: tasks, isLoading, error } = useQuery(getTasks)
  const createTaskFn = useAction(createTask)
  const togglePriorityFn = useAction(togglePriority)

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault()
    try {
      const target = event.target as any
      const description = target.description.value
      target.reset()
      await createTaskFn({ description })
    } catch (err: any) {
      window.alert('Error: ' + err.message)
    }
  }

  return (
    <div style={{ padding: '20px' }}>
      <h1>Task Priority Application</h1>

      <form onSubmit={handleSubmit} style={{ marginBottom: '20px' }}>
        <input 
          type="text" 
          name="description" 
          placeholder="New Task" 
          required 
          style={{ marginRight: '10px' }}
        />
        <button type="submit">Add Task</button>
      </form>

      {isLoading && <div>Loading...</div>}
      {error && <div>Error: {error.message}</div>}

      {tasks && tasks.length === 0 && <div>No tasks found.</div>}

      {tasks && tasks.map((task) => (
        <div key={task.id} style={{ marginBottom: '10px', display: 'flex', alignItems: 'center', gap: '10px' }}>
          <span>{task.description}</span>
          <span>- Priority: {task.priority}</span>
          <button onClick={() => togglePriorityFn({ id: task.id })}>
            Toggle Priority
          </button>
        </div>
      ))}
    </div>
  )
}

